solution_code:
#include <iostream>

class Counter {
public:
    int count{0};

    Counter& add(int n) { count += n; return *this; }
    Counter& subtract(int n) { count -= n; return *this; }
    Counter& reset() { count = 0; return *this; }
    int value() const { return count; }
};

int main() {
    int a, b, c;
    std::cin >> a >> b >> c;

    Counter ctr;
    ctr.reset().add(a).subtract(b).add(c);

    std::cout << "Result: " << ctr.value() << '\n';
    return 0;
}

